  5→//! Saddle command - Return context needed to saddle up on a Heat
  6→
  7→use std::fs;
  8→use std::path::PathBuf;
  9→
 10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
 12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
 13→use crate::jjrs_steeplechase::{jjrs_get_entries, jjrs_ReinArgs};
 14→use crate::jjrq_query::jjrq_resolve_default_heat;
 15→use crate::jjrpd_parade::{jjrpd_print_file_bitmap, jjrpd_print_commit_swimlanes};
 16→
 17→/// Arguments for saddle command
 18→#[derive(clap::Args, Debug)]
 19→pub struct jjrsd_SaddleArgs {
 20→    /// Path to the Gallops JSON file
 21→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 22→    pub file: PathBuf,
 23→
 24→    /// Target Heat identity (Firemark). If omitted, uses first racing heat.
 25→    pub firemark: Option<String>,
 26→}
 27→
 28→/// Run the saddle command - return Heat context
 29→pub async fn jjrsd_run_saddle(args: jjrsd_SaddleArgs) -> i32 {
 30→    let gallops = match Gallops::jjrg_load(&args.file) {
 31→        Ok(g) => g,
 32→        Err(e) => {
 33→            eprintln!("jjx_orient: error: {}", e);
 34→            return 1;
 35→        }
 36→    };
 37→
 38→    // Collect racing heats and display summary table
 39→    {
 40→        let mut racing_heats: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heats.iter()
 41→            .filter(|(_, heat)| heat.status == HeatStatus::Racing)
 42→            .collect();
 43→
 44→        // Sort by key for stability
 45→        racing_heats.sort_by(|a, b| a.0.cmp(b.0));
 46→
 47→        if !racing_heats.is_empty() {
 48→            let mut table = jjrp_Table::jjrp_new(vec![
 49→                jjrp_Column::new("₣Fire", jjrp_Align::Left),
 50→                jjrp_Column::new("Silks", jjrp_Align::Left),
 51→                jjrp_Column::new("Status", jjrp_Align::Left),
 52→                jjrp_Column::new("Done", jjrp_Align::Right),
 53→                jjrp_Column::new("Total", jjrp_Align::Right),
 54→            ]);
 55→
 56→            // Measure all rows to compute column widths
 57→            for (key, heat) in &racing_heats {
 58→                let defined_count = heat.paces.values().filter(|pace| {
 59→                    if let Some(tack) = pace.tacks.first() {
 60→                        tack.state != PaceState::Abandoned
 61→                    } else {
 62→                        true
 63→                    }
 64→                }).count();
 65→
 66→                let completed_count = heat.paces.values().filter(|pace| {
 67→                    if let Some(tack) = pace.tacks.first() {
 68→                        tack.state == PaceState::Complete
 69→                    } else {
 70→                        false
 71→                    }
 72→                }).count();
 73→
 74→                table.jjrp_measure(&[
 75→                    key,
 76→                    &heat.silks,
 77→                    "racing",
 78→                    &completed_count.to_string(),
 79→                    &defined_count.to_string(),
 80→                ]);
 81→            }
 82→
 83→            // Print header and separator
 84→            println!("Racing-heats:");
 85→            table.jjrp_print_header();
 86→            table.jjrp_print_separator();
 87→
 88→            // Print data rows
 89→            for (key, heat) in &racing_heats {
 90→                let defined_count = heat.paces.values().filter(|pace| {
 91→                    if let Some(tack) = pace.tacks.first() {
 92→                        tack.state != PaceState::Abandoned
 93→                    } else {
 94→                        true
 95→                    }
 96→                }).count();
 97→
 98→                let completed_count = heat.paces.values().filter(|pace| {
 99→                    if let Some(tack) = pace.tacks.first() {
100→                        tack.state == PaceState::Complete
101→                    } else {
102→                        false
103→                    }
104→                }).count();
105→
106→                table.jjrp_print_row(&[
107→                    key,
108→                    &heat.silks,
109→                    "racing",
110→                    &completed_count.to_string(),
111→                    &defined_count.to_string(),
112→                ]);
113→            }
114→
115→            println!();
116→        }
117→    }
118→
119→    // Resolve firemark: use provided value or auto-select first racing heat
120→    let firemark_str = match args.firemark {
121→        Some(fm) => fm,
122→        None => {
123→            match jjrq_resolve_default_heat(&gallops) {
124→                Ok(fm) => fm,
125→                Err(e) => {
126→                    eprintln!("jjx_orient: error: {}", e);
127→                    return 1;
128→                }
129→            }
130→        }
131→    };
132→
133→    let firemark = match Firemark::jjrf_parse(&firemark_str) {
134→        Ok(fm) => fm,
135→        Err(e) => {
136→            eprintln!("jjx_orient: error: {}", e);
137→            return 1;
138→        }
139→    };
140→
141→    let heat_key = firemark.jjrf_display();
142→    let heat = match gallops.heats.get(&heat_key) {
143→        Some(h) => h,
144→        None => {
145→            eprintln!("jjx_orient: error: Heat '{}' not found", heat_key);
146→            return 1;
147→        }
148→    };
149→
150→    // Check if heat is stabled (cannot saddle stabled heat)
151→    if heat.status == HeatStatus::Stabled {
152→        eprintln!("jjx_orient: error: Cannot saddle stabled heat '{}'", heat_key);
153→        return 1;
154→    }
155→
156→    // Read paddock file content
157→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
158→        Ok(content) => content,
159→        Err(e) => {
160→            eprintln!("jjx_orient: error reading paddock file '{}': {}", heat.paddock_file, e);
161→            return 1;
162→        }
163→    };
164→
165→    // Get recent steeplechase entries
166→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
167→        firemark: firemark.jjrf_as_str().to_string(),
168→        limit: 10,
169→    }).unwrap_or_default();
170→
171→    // Find first actionable pace (rough or bridled)
172→    let mut pace_coronet: Option<String> = None;
173→    let mut pace_silks: Option<String> = None;
174→    let mut pace_state: Option<String> = None;
175→    let mut spec: Option<String> = None;
176→    let mut direction: Option<String> = None;
177→
178→    for coronet_key in &heat.order {
179→        if let Some(pace) = heat.paces.get(coronet_key) {
180→            if let Some(tack) = pace.tacks.first() {
181→                match tack.state {
182→                    PaceState::Rough | PaceState::Bridled => {
183→                        pace_coronet = Some(coronet_key.clone());
184→                        pace_silks = Some(tack.silks.clone());
185→                        pace_state = Some(match tack.state {
186→                            PaceState::Rough => "rough".to_string(),
187→                            PaceState::Bridled => "bridled".to_string(),
188→                            _ => unreachable!(),
189→                        });
190→                        spec = Some(tack.text.clone());
191→                        if tack.state == PaceState::Bridled {
192→                            direction = tack.direction.clone();
193→                        }
194→                        break;
195→                    }
196→                    _ => continue,
197→                }
198→            }
199→        }
200→    }
201→
202→    // Determine heat status string
203→    let status_str = match heat.status {
204→        HeatStatus::Racing => "racing",
205→        HeatStatus::Stabled => "stabled",
206→        HeatStatus::Retired => "retired",
207→    };
208→
209→    // Output plain text format
210→    println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
211→    println!("Paddock: {}", heat.paddock_file);
212→    println!();
213→    println!("Paddock-content:");
214→    for line in paddock_content.lines() {
215→        println!("  {}", line);
216→    }
217→    println!();
218→
219→    if let Some(coronet) = pace_coronet {
220→        if let Some(silks) = pace_silks {
221→            if let Some(state) = pace_state {
222→                println!("Next: {} ({}) [{}]", silks, coronet, state);
223→                println!();
224→                if let Some(spec_text) = spec {
225→                    println!("Docket:");
226→                    for line in spec_text.lines() {
227→                        println!("  {}", line);
228→                    }
229→                    println!();
230→                }
231→                if let Some(dir_text) = direction {
232→                    println!("Warrant:");
233→                    for line in dir_text.lines() {
234→                        println!("  {}", line);
235→                    }
236→                    println!();
237→                }
238→                eprintln!();
239→                if state == "bridled" {
240→                    eprintln!("Recommended: /jjc-heat-mount {} to execute", firemark.jjrf_as_str());
241→                } else {
242→                    eprintln!("Recommended: /jjc-pace-bridle {} or /jjc-heat-mount {}", coronet, firemark.jjrf_as_str());
243→                }
244→            }
245→        }
246→    }
247→
248→    // Output recent work table
249→    // Filter entries to only show action codes 'n' (notch), 'A' (approach), 'd' (discussion)
250→    let filtered_work: Vec<_> = recent_work.iter().filter(|entry| {
251→        if let Some(ref action) = entry.action {
252→            action == "n" || action == "A" || action == "d"
253→        } else {
254→            false
255→        }
256→    }).collect();
257→
258→    if !filtered_work.is_empty() {
259→        println!("Recent-work:");
260→
261→        let mut table = jjrp_Table::jjrp_new(vec![
262→            jjrp_Column::new("Commit", jjrp_Align::Left),
263→            jjrp_Column::new("Identity", jjrp_Align::Left),
264→            jjrp_Column::new("Subject", jjrp_Align::Left),
265→        ]);
266→
267→        // Measure all rows to compute column widths
268→        for entry in &filtered_work {
269→            let identity_str = if let Some(ref coronet) = entry.coronet {
270→                coronet.clone()
271→            } else {
272→                heat_key.clone()
273→            };
274→            table.jjrp_measure(&[
275→                &entry.commit,
276→                &identity_str,
277→                &entry.subject,
278→            ]);
279→        }
280→
281→        // Print header and separator
282→        table.jjrp_print_header();
283→        table.jjrp_print_separator();
284→
285→        // Print data rows
286→        for entry in &filtered_work {
287→            let identity_str = if let Some(ref coronet) = entry.coronet {
288→                coronet.clone()
289→            } else {
290→                heat_key.clone()
291→            };
292→            table.jjrp_print_row(&[
293→                &entry.commit,
294→                &identity_str,
295→                &entry.subject,
296→            ]);
297→        }
298→    }
299→
300→    // Always show file-touch bitmap and commit swim lanes after recent work
301→    jjrpd_print_file_bitmap(&firemark, heat);
302→    jjrpd_print_commit_swimlanes(&firemark, heat);
303→
304→    // Call invitatory to check/create officium marker
305→    if let Err(e) = vvc::vvcp_invitatory().await {
306→        eprintln!("jjx_orient: warning: invitatory failed: {}", e);
307→    }
308→
309→    0
310→}
